/// Env-gated activation dumps for bisecting GPU-vs-CPU numerical divergence
/// (used to debug the DeepSeek-V2-Lite MLA forward). Set
/// `HI_MLA_DEBUG_DUMP=/path/file.jsonl` and run the CPU reference and the CUDA
/// forward with the same tokens (separate processes / paths); each tagged
/// tensor appends one JSON line with its element count, L2 norm, the first 8
/// values, and 8 evenly-strided samples. Diff the two files record-by-record to
/// find the first divergent tensor. Zero-cost when the env var is unset.
pub(crate) mod mla_debug {
    use std::fs::File;
    use std::io::Write;
    use std::sync::atomic::{AtomicUsize, Ordering};
    use std::sync::{Mutex, OnceLock};

    static LAYER: AtomicUsize = AtomicUsize::new(0);

    fn sink() -> Option<&'static Mutex<File>> {
        static SINK: OnceLock<Option<Mutex<File>>> = OnceLock::new();
        SINK.get_or_init(|| {
            let path = std::env::var("HI_MLA_DEBUG_DUMP").ok()?;
            let file = File::options().create(true).append(true).open(path).ok()?;
            Some(Mutex::new(file))
        })
        .as_ref()
    }

    pub(crate) fn enabled() -> bool {
        sink().is_some()
    }

    /// Records the layer index that `dump_scoped` tags with (`L{n}.<tag>`).
    pub(crate) fn set_layer(layer: usize) {
        if enabled() {
            LAYER.store(layer, Ordering::Relaxed);
        }
    }

    /// Dumps a tensor scoped to the current layer (`L{n}.<tag>`).
    pub(crate) fn dump_scoped(tag: &str, values: &[f32]) {
        if enabled() {
            let layer = LAYER.load(Ordering::Relaxed);
            dump(&format!("L{layer}.{tag}"), values);
        }
    }

    /// Dumps rows-of-values (the CPU reference's `Vec<Vec<f32>>` layout) scoped
    /// to the current layer; rows are concatenated to match the GPU tensors.
    pub(crate) fn dump_scoped_rows(tag: &str, rows: &[Vec<f32>]) {
        if enabled() {
            let flat: Vec<f32> = rows.iter().flatten().copied().collect();
            dump_scoped(tag, &flat);
        }
    }

    pub(crate) fn dump_rows(tag: &str, rows: &[Vec<f32>]) {
        if enabled() {
            let flat: Vec<f32> = rows.iter().flatten().copied().collect();
            dump(tag, &flat);
        }
    }

    pub(crate) fn dump(tag: &str, values: &[f32]) {
        let Some(sink) = sink() else { return };
        let l2 = values
            .iter()
            .map(|value| f64::from(*value) * f64::from(*value))
            .sum::<f64>()
            .sqrt();
        let first: Vec<f32> = values.iter().take(8).copied().collect();
        let stride = (values.len() / 8).max(1);
        let sample: Vec<f32> = values.iter().step_by(stride).take(8).copied().collect();
        if let Ok(mut file) = sink.lock() {
            let _ = writeln!(
                file,
                "{{\"tag\":\"{tag}\",\"n\":{},\"l2\":{l2:.6e},\"first\":{first:?},\"sample\":{sample:?}}}",
                values.len()
            );
        }
        dump_full(tag, values);
    }

    /// With `HI_MLA_DEBUG_DUMP_FULL=<dir>` additionally appends the raw f32
    /// little-endian values to `<dir>/<tag>.bin` (per-token records append to
    /// the same file, matching the flattened GPU layout) for elementwise diffs.
    fn dump_full(tag: &str, values: &[f32]) {
        static DIR: OnceLock<Option<String>> = OnceLock::new();
        let Some(dir) = DIR
            .get_or_init(|| std::env::var("HI_MLA_DEBUG_DUMP_FULL").ok())
            .as_ref()
        else {
            return;
        };
        let name: String = tag
            .chars()
            .map(|c| {
                if c.is_ascii_alphanumeric() || c == '.' || c == '_' {
                    c
                } else {
                    '_'
                }
            })
            .collect();
        let Ok(mut file) = File::options()
            .create(true)
            .append(true)
            .open(format!("{dir}/{name}.bin"))
        else {
            return;
        };
        let mut bytes = Vec::with_capacity(values.len() * 4);
        for value in values {
            bytes.extend_from_slice(&value.to_le_bytes());
        }
        let _ = file.write_all(&bytes);
    }
}

const CUDA_ATTENTION_FAST_HEAD_DIM_MAX: usize = 512;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum CudaExecution {
    Gpu,
    CpuReference,
}

impl CudaExecution {
    pub fn label(self) -> &'static str {
        match self {
            Self::Gpu => "gpu",
            Self::CpuReference => "cpu-reference",
        }
    }

    pub fn default_for_build() -> Self {
        if cfg!(feature = "native-cuda") {
            Self::Gpu
        } else {
            Self::CpuReference
        }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum CudaKvCacheMode {
    Legacy,
    Paged,
}

impl CudaKvCacheMode {
    pub fn label(self) -> &'static str {
        match self {
            Self::Legacy => "legacy",
            Self::Paged => "paged",
        }
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct CudaAttentionHealth {
    status: &'static str,
    detail: String,
}

fn qwen_attention_key_value_head_dims(qwen: &QwenGgufConfig) -> Result<(usize, usize)> {
    let qk_head_dim = qwen
        .attention_key_head_dim()
        .map(usize::try_from)
        .transpose()
        .context("qwen attention key head dimension does not fit usize")?
        .ok_or_else(|| {
            anyhow!(
                "qwen attention key length is incompatible with embedding length {} and attention heads {}",
                qwen.embedding_length,
                qwen.attention_head_count
            )
        })?;
    let v_head_dim = qwen
        .attention_value_head_dim()
        .map(usize::try_from)
        .transpose()
        .context("qwen attention value head dimension does not fit usize")?
        .ok_or_else(|| {
            anyhow!(
                "qwen attention value length is incompatible with embedding length {} and attention heads {}",
                qwen.embedding_length,
                qwen.attention_head_count
            )
        })?;
    Ok((qk_head_dim, v_head_dim))
}

fn cuda_attention_health_status(
    execution: CudaExecution,
    kv_cache_mode: CudaKvCacheMode,
    paged_kv_available: bool,
    head_dims: Option<(usize, usize)>,
    multimodal_generation: bool,
) -> CudaAttentionHealth {
    let head_dim_label = head_dims
        .map(|(qk_head_dim, v_head_dim)| {
            if qk_head_dim == v_head_dim {
                qk_head_dim.to_string()
            } else {
                format!("qk:{qk_head_dim},v:{v_head_dim}")
            }
        })
        .unwrap_or_else(|| "unknown".to_string());
    let fast_head_dim = head_dims.is_some_and(|(qk_head_dim, v_head_dim)| {
        qk_head_dim.max(v_head_dim) <= CUDA_ATTENTION_FAST_HEAD_DIM_MAX
    });
    let multimodal = cuda_attention_multimodal_detail(
        multimodal_generation,
        fast_head_dim,
        kv_cache_mode,
        paged_kv_available,
    );
    let wide_kernel_detail = format!(
        ",wide_kernel=tiled-wide,wide_head_dim_max={}",
        CUDA_ATTENTION_FAST_HEAD_DIM_MAX
    );

    if execution != CudaExecution::Gpu {
        return CudaAttentionHealth {
            status: "legacy",
            detail: format!(
                "mode=disabled,head_dim={head_dim_label},head_dim_max={}{wide_kernel_detail},kv_cache=disabled,decode=legacy(paths=single-text|batched-text,fallback_reason=cpu-reference),prefill=legacy(paths=text|batched-text|multimodal,fallback_reason=cpu-reference),multimodal=disabled(prompt_embeddings=unavailable,fallback_reason=cpu-reference)",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX
            ),
        };
    }

    if head_dims.is_none() {
        return CudaAttentionHealth {
            status: "legacy",
            detail: format!(
                "mode=legacy,head_dim=unknown,head_dim_max={}{wide_kernel_detail},kv_cache={},decode=legacy(paths=single-text|batched-text,fallback_reason=invalid-head-dim),prefill=legacy(paths=text|batched-text|multimodal,fallback_reason=invalid-head-dim),multimodal=legacy(prompt_embeddings=legacy,fallback_reason=invalid-head-dim)",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX,
                kv_cache_mode.label(),
            ),
        };
    }

    match (kv_cache_mode, paged_kv_available, fast_head_dim) {
        (CudaKvCacheMode::Paged, true, true) => CudaAttentionHealth {
            status: "tiled-paged",
            detail: format!(
                "mode=tiled-paged,head_dim={head_dim_label},head_dim_max={}{wide_kernel_detail},kv_cache=paged,decode=tiled-paged(paths=single-text|batched-text,fallback_reason=none),decode_fallback=paged(head_dim_min={},fallback_reason=wide-head),prefill=tiled-contiguous(paths=text|batched-text|multimodal,fallback_reason=none),prefill_fallback=legacy(head_dim_min={},fallback_reason=wide-head),multimodal={multimodal}",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX,
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX + 1,
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX + 1,
            ),
        },
        (CudaKvCacheMode::Paged, true, false) => CudaAttentionHealth {
            status: "paged-generic",
            detail: format!(
                "mode=paged-generic,head_dim={head_dim_label},head_dim_max={}{wide_kernel_detail},kv_cache=paged,decode=paged-generic(paths=single-text|batched-text,fallback_from=tiled-paged,fallback_reason=wide-head),prefill=contiguous-generic(paths=text|batched-text|multimodal,fallback_from=tiled-contiguous,fallback_reason=wide-head),multimodal={multimodal}",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX
            ),
        },
        (CudaKvCacheMode::Paged, false, true) => CudaAttentionHealth {
            status: "flash-online",
            detail: format!(
                "mode=flash-online,head_dim={head_dim_label},head_dim_max={}{wide_kernel_detail},kv_cache=paged-unavailable,decode=flash-online(paths=single-text|batched-text,fallback_reason=paged-kv-unavailable),decode_fallback=legacy(head_dim_min={},fallback_reason=wide-head),prefill=tiled-contiguous(paths=text|batched-text|multimodal,fallback_reason=paged-kv-unavailable),prefill_fallback=legacy(head_dim_min={},fallback_reason=wide-head),multimodal={multimodal}",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX,
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX + 1,
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX + 1,
            ),
        },
        (CudaKvCacheMode::Paged, false, false) => CudaAttentionHealth {
            status: "contiguous-generic",
            detail: format!(
                "mode=contiguous-generic,head_dim={head_dim_label},head_dim_max={}{wide_kernel_detail},kv_cache=paged-unavailable,decode=contiguous-generic(paths=single-text|batched-text,fallback_reason=paged-kv-unavailable|wide-head),prefill=contiguous-generic(paths=text|batched-text|multimodal,fallback_reason=paged-kv-unavailable|wide-head),multimodal={multimodal}",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX
            ),
        },
        (CudaKvCacheMode::Legacy, _, true) => CudaAttentionHealth {
            status: "flash-online",
            detail: format!(
                "mode=flash-online,head_dim={head_dim_label},head_dim_max={}{wide_kernel_detail},kv_cache=legacy,decode=flash-online(paths=single-text|batched-text,fallback_reason=none),decode_fallback=legacy(head_dim_min={},fallback_reason=wide-head),prefill=tiled-contiguous(paths=text|batched-text|multimodal,fallback_reason=none),prefill_fallback=legacy(head_dim_min={},fallback_reason=wide-head),multimodal={multimodal}",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX,
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX + 1,
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX + 1,
            ),
        },
        (CudaKvCacheMode::Legacy, _, false) => CudaAttentionHealth {
            status: "contiguous-generic",
            detail: format!(
                "mode=contiguous-generic,head_dim={head_dim_label},head_dim_max={}{wide_kernel_detail},kv_cache=legacy,decode=contiguous-generic(paths=single-text|batched-text,fallback_from=flash-online,fallback_reason=wide-head),prefill=contiguous-generic(paths=text|batched-text|multimodal,fallback_from=tiled-contiguous,fallback_reason=wide-head),multimodal={multimodal}",
                CUDA_ATTENTION_FAST_HEAD_DIM_MAX
            ),
        },
    }
}

fn cuda_attention_multimodal_detail(
    multimodal_generation: bool,
    fast_head_dim: bool,
    kv_cache_mode: CudaKvCacheMode,
    paged_kv_available: bool,
) -> &'static str {
    match (
        multimodal_generation,
        fast_head_dim,
        kv_cache_mode,
        paged_kv_available,
    ) {
        (true, true, CudaKvCacheMode::Paged, true) => {
            "tiled-paged(prompt_embeddings=tiled-paged,prefill=tiled-contiguous,decode=tiled-paged,fallback_reason=none)"
        }
        (true, true, _, _) => {
            "tiled-contiguous(prompt_embeddings=tiled-contiguous,fallback_reason=none)"
        }
        (true, false, _, _) => {
            "contiguous-generic(prompt_embeddings=contiguous-generic,fallback_from=tiled-contiguous,fallback_reason=wide-head)"
        }
        (false, _, _, _) => "text-only(prompt_embeddings=unavailable,fallback_reason=no-mmproj)",
    }
}

