    /// glm-dsa fixture pair: layer 0 = dense-FFN MLA block, layer 1 = sigmoid
    /// MoE MLA block. `split_kv_b` picks whether the kv_b projection ships as
    /// the per-head split `attn_k_b`/`attn_v_b` rank-3 tensors (k_b stored
    /// transposed, glm-dsa style) or pre-fused `attn_kv_b` with IDENTICAL
    /// values — the two fixtures must produce matching outputs, which pins the
    /// load-time synthesis transpose exactly.
    /// Dims: embed=4, heads=2, q_lora=3, kv_lora=3, nope=2, rope=4 (qk_mla=6),
    /// v_head=2; experts=3 top-2, sigmoid gating (func 2), scale 2.5.
    ///
    /// rope=4 is load-bearing: the interleaved (glm-dsa/DeepSeek) and NEOX
    /// split-half partial-rope styles coincide at rope=2 — DeepSeek-V2-Lite
    /// shipped broken behind exactly that degenerate fixture — and only
    /// diverge from rope=4 up, so this fixture distinguishes the styles (see
    /// native_cuda_glm_dsa_matches_cpu_reference_and_pins_interleaved_pe_rope).
    #[cfg(feature = "native-cuda")]
    fn write_reference_glm_dsa(path: &Path, split_kv_b: bool) {
        const HEADS: usize = 2;
        const NOPE: usize = 2;
        const ROPE: usize = 4;
        const V_HEAD: usize = 2;
        const KV_LORA: usize = 3;
        // Fused kv_b rows are per head [k_nope rows | v rows], each row holding
        // kv_lora input weights. Values on the 1/64 grid (exact in f16).
        let fused_kv_b = qwen35_fixture_values(HEADS * (NOPE + V_HEAD) * KV_LORA, 41);
        let mut tensors = vec![
            tensor_f16_exact(
                "token_embd.weight",
                vec![4, 3],
                &qwen35_fixture_values(12, 31),
            ),
            tensor_f32(
                "output_norm.weight",
                vec![4],
                &qwen35_fixture_norm_values(4, 32),
            ),
        ];
        for layer in 0..2usize {
            let p = format!("blk.{layer}");
            let seed = (layer as u32) * 100;
            tensors.extend([
                tensor_f32(
                    &format!("{p}.attn_norm.weight"),
                    vec![4],
                    &qwen35_fixture_norm_values(4, seed + 33),
                ),
                tensor_f32(
                    &format!("{p}.ffn_norm.weight"),
                    vec![4],
                    &qwen35_fixture_norm_values(4, seed + 34),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_q_a.weight"),
                    vec![4, 3],
                    &qwen35_fixture_values(12, seed + 35),
                ),
                tensor_f32(
                    &format!("{p}.attn_q_a_norm.weight"),
                    vec![3],
                    &qwen35_fixture_norm_values(3, seed + 36),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_q_b.weight"),
                    vec![3, (HEADS * (NOPE + ROPE)) as u64],
                    &qwen35_fixture_values(3 * HEADS * (NOPE + ROPE), seed + 37),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_kv_a_mqa.weight"),
                    vec![4, (KV_LORA + ROPE) as u64],
                    &qwen35_fixture_values(4 * (KV_LORA + ROPE), seed + 38),
                ),
                tensor_f32(
                    &format!("{p}.attn_kv_a_norm.weight"),
                    vec![3],
                    &qwen35_fixture_norm_values(3, seed + 39),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_output.weight"),
                    vec![4, 4],
                    &qwen35_fixture_values(16, seed + 40),
                ),
            ]);
            if split_kv_b {
                // k_b[n, l, h] = fused[(h*(NOPE+V_HEAD) + n)*KV_LORA + l]
                let mut k_b = vec![0.0f32; NOPE * KV_LORA * HEADS];
                let mut v_b = vec![0.0f32; KV_LORA * V_HEAD * HEADS];
                for h in 0..HEADS {
                    for n in 0..NOPE {
                        for l in 0..KV_LORA {
                            k_b[h * NOPE * KV_LORA + l * NOPE + n] =
                                fused_kv_b[(h * (NOPE + V_HEAD) + n) * KV_LORA + l];
                        }
                    }
                    for vd in 0..V_HEAD {
                        for l in 0..KV_LORA {
                            v_b[h * KV_LORA * V_HEAD + vd * KV_LORA + l] =
                                fused_kv_b[(h * (NOPE + V_HEAD) + NOPE + vd) * KV_LORA + l];
                        }
                    }
                }
                tensors.push(tensor_f16_exact(
                    &format!("{p}.attn_k_b.weight"),
                    vec![NOPE as u64, KV_LORA as u64, HEADS as u64],
                    &k_b,
                ));
                tensors.push(tensor_f16_exact(
                    &format!("{p}.attn_v_b.weight"),
                    vec![KV_LORA as u64, V_HEAD as u64, HEADS as u64],
                    &v_b,
                ));
            } else {
                tensors.push(tensor_f16_exact(
                    &format!("{p}.attn_kv_b.weight"),
                    vec![KV_LORA as u64, (HEADS * (NOPE + V_HEAD)) as u64],
                    &fused_kv_b,
                ));
            }
            if layer == 0 {
                tensors.extend([
                    tensor_f16_exact(
                        &format!("{p}.ffn_gate.weight"),
                        vec![4, 4],
                        &qwen35_fixture_values(16, seed + 44),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_up.weight"),
                        vec![4, 4],
                        &qwen35_fixture_values(16, seed + 45),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_down.weight"),
                        vec![4, 4],
                        &qwen35_fixture_values(16, seed + 46),
                    ),
                ]);
            } else {
                tensors.extend([
                    tensor_f32(
                        &format!("{p}.ffn_gate_inp.weight"),
                        vec![4, 3],
                        &qwen35_fixture_values(12, seed + 47),
                    ),
                    tensor_f32(
                        &format!("{p}.exp_probs_b.bias"),
                        vec![3],
                        &qwen35_fixture_values(3, seed + 48),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_gate_exps.weight"),
                        vec![4, 2, 3],
                        &qwen35_fixture_values(24, seed + 49),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_up_exps.weight"),
                        vec![4, 2, 3],
                        &qwen35_fixture_values(24, seed + 50),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_down_exps.weight"),
                        vec![2, 4, 3],
                        &qwen35_fixture_values(24, seed + 51),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_gate_shexp.weight"),
                        vec![4, 2],
                        &qwen35_fixture_values(8, seed + 52),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_up_shexp.weight"),
                        vec![4, 2],
                        &qwen35_fixture_values(8, seed + 53),
                    ),
                    tensor_f16_exact(
                        &format!("{p}.ffn_down_shexp.weight"),
                        vec![2, 4],
                        &qwen35_fixture_values(8, seed + 54),
                    ),
                ]);
            }
        }
        write_glm_dsa_gguf(path, tensors);
    }

    #[cfg(feature = "native-cuda")]
    fn write_glm_dsa_gguf(path: &Path, tensors: Vec<TestTensor>) {
        let mut data = Vec::new();
        let tensors = tensors
            .into_iter()
            .map(|mut tensor| {
                pad_to_alignment(&mut data, 32);
                tensor.offset = data.len() as u64;
                data.extend_from_slice(&tensor.bytes);
                tensor
            })
            .collect::<Vec<_>>();

        let mut bytes = Vec::new();
        bytes.extend_from_slice(b"GGUF");
        write_u32(&mut bytes, 3);
        write_u64(&mut bytes, tensors.len() as u64);
        write_u64(&mut bytes, 25);

        write_kv_string(&mut bytes, "general.architecture", "glm-dsa");
        write_kv_string(&mut bytes, "general.name", "cpu-reference-glm-dsa");
        write_kv_u32(&mut bytes, "general.alignment", 32);
        write_kv_u32(&mut bytes, "general.file_type", 1);
        write_kv_u32(&mut bytes, "glm-dsa.context_length", 128);
        write_kv_u32(&mut bytes, "glm-dsa.embedding_length", 4);
        write_kv_u32(&mut bytes, "glm-dsa.feed_forward_length", 4);
        write_kv_u32(&mut bytes, "glm-dsa.block_count", 2);
        write_kv_u32(&mut bytes, "glm-dsa.attention.head_count", 2);
        write_kv_u32(&mut bytes, "glm-dsa.attention.head_count_kv", 1);
        write_kv_f32(
            &mut bytes,
            "glm-dsa.attention.layer_norm_rms_epsilon",
            1.0e-6,
        );
        // Base 10 (not the usual 1e4) so BOTH rope pairs rotate by O(1)
        // radians within a 3-token context: at base 1e4 the second pair's
        // frequency is 1e-2 and the interleaved-vs-split-half difference
        // stays within ~1e-2 of the logits, too close to the parity
        // tolerance to pin the style robustly.
        write_kv_f32(&mut bytes, "glm-dsa.rope.freq_base", 10.0);
        // rope=4 / key_mla=6 (nope 2 + rope 4): the minimum rope dim where the
        // interleaved and split-half partial-rope styles diverge.
        write_kv_u32(&mut bytes, "glm-dsa.rope.dimension_count", 4);
        write_kv_u32(&mut bytes, "glm-dsa.attention.q_lora_rank", 3);
        write_kv_u32(&mut bytes, "glm-dsa.attention.kv_lora_rank", 3);
        write_kv_u32(&mut bytes, "glm-dsa.attention.key_length_mla", 6);
        write_kv_u32(&mut bytes, "glm-dsa.attention.value_length_mla", 2);
        // The real GLM-5.2 gguf ALSO carries the LATENT compressed-KV dims in
        // the plain key/value_length keys (576/512 = kv_lora + qk_rope /
        // kv_lora); mirror that (3+4 / 3) so the fixture exercises
        // qwen_cpu::mla_aware_value_head_dim (the per-head v dim must come
        // from value_length_mla, not the latent width) and the
        // validate_qwen_tensors_mla_aware shim for the validator's
        // latent-width attn_output false positive.
        write_kv_u32(&mut bytes, "glm-dsa.attention.key_length", 7);
        write_kv_u32(&mut bytes, "glm-dsa.attention.value_length", 3);
        write_kv_u32(&mut bytes, "glm-dsa.expert_count", 3);
        write_kv_u32(&mut bytes, "glm-dsa.expert_feed_forward_length", 2);
        write_kv_u32(&mut bytes, "glm-dsa.expert_used_count", 2);
        write_kv_u32(&mut bytes, "glm-dsa.expert_gating_func", 2);
        write_kv_f32(&mut bytes, "glm-dsa.expert_weights_scale", 2.5);
        write_kv_string_array(&mut bytes, "tokenizer.ggml.tokens", &["a", "b", "c"]);

        for tensor in tensors {
            write_string(&mut bytes, &tensor.name);
            write_u32(&mut bytes, tensor.dims.len() as u32);
            for dim in tensor.dims {
                write_u64(&mut bytes, dim);
            }
            write_u32(&mut bytes, tensor.dtype);
            write_u64(&mut bytes, tensor.offset);
        }

        pad_to_alignment(&mut bytes, 32);
        bytes.extend(data);
        fs::write(path, bytes).unwrap();
    }

    /// Split k_b/v_b and pre-fused kv_b fixtures with identical weights must
    /// generate identical outputs: pins the load-time synthesis transpose and
    /// the sigmoid + selection-bias + scale MoE routing end to end.
    #[cfg(feature = "native-cuda")]
    #[test]
    fn native_cuda_glm_dsa_split_kv_b_matches_fused() {
        use hi_gguf::GgufFile;

        let split_path = tempfile_path("gpu-glm-dsa-split");
        let fused_path = tempfile_path("gpu-glm-dsa-fused");
        write_reference_glm_dsa(&split_path, true);
        write_reference_glm_dsa(&fused_path, false);

        let split_gguf = GgufFile::open(&split_path).unwrap();
        let fused_gguf = GgufFile::open(&fused_path).unwrap();
        let split_model = crate::gpu::CudaQwenGpuModel::from_gguf(&split_gguf).unwrap();
        let fused_model = crate::gpu::CudaQwenGpuModel::from_gguf(&fused_gguf).unwrap();

        // The synthesized fused projection must exist on the split model.
        assert!(split_model.has_matrix("blk.0.attn_kv_b.weight"));
        assert!(split_model.has_matrix("blk.1.attn_kv_b.weight"));

        let split_logits = split_model.full_context_logits_host(&[0, 1, 2]).unwrap();
        let fused_logits = fused_model.full_context_logits_host(&[0, 1, 2]).unwrap();
        assert_close_vec(&split_logits, &fused_logits);
        assert!(split_logits.iter().all(|value| value.is_finite()));

        assert_eq!(
            split_model.generate_greedy_tokens(&[1], 3, None).unwrap(),
            fused_model.generate_greedy_tokens(&[1], 3, None).unwrap()
        );
    }

    /// Full CPU==GPU parity on the glm-dsa fixture (MLA q_lora/kv_lora,
    /// sigmoid noaux_tc routing, shared expert) at qk_rope=4 — where the
    /// interleaved and split-half pe-rope styles genuinely diverge — plus a
    /// golden-logits pin of the INTERLEAVED style itself. Both backends share
    /// qwen_cpu::mla_pe_rope_interleaved, so parity alone cannot catch a
    /// style flip applied to both sides at once (exactly how DeepSeek-V2-Lite
    /// shipped broken); the goldens can. The split-half logits recorded below
    /// were measured on this fixture and are asserted FAR, proving the
    /// fixture distinguishes the styles.
    #[cfg(feature = "native-cuda")]
    #[test]
    fn native_cuda_glm_dsa_matches_cpu_reference_and_pins_interleaved_pe_rope() {
        use hi_gguf::GgufFile;

        let path = tempfile_path("gpu-glm-dsa-cpu-parity");
        write_reference_glm_dsa(&path, false);
        let gguf = GgufFile::open(&path).unwrap();
        let model = crate::gpu::CudaQwenGpuModel::from_gguf(&gguf).unwrap();
        let cpu = crate::qwen_cpu::QwenCpuReference::load(&path).unwrap();
        assert_eq!(cpu.config().architecture, "glm-dsa");

        let tokens = [0u32, 1, 2, 2, 0, 1];
        let cpu_logits = cpu
            .forward(&tokens)
            .unwrap()
            .into_iter()
            .flatten()
            .collect::<Vec<_>>();
        let gpu_logits = model.full_context_logits_host(&tokens).unwrap();
        assert_close_vec(&gpu_logits, &cpu_logits);
        assert!(gpu_logits.iter().all(|value| value.is_finite()));

        assert_eq!(
            model.generate_greedy_tokens(&[1], 4, None).unwrap(),
            cpu.generate_greedy(&[1], 4).unwrap()
        );

        // Golden full-context logits (6 tokens x vocab 3) under interleaved
        // pe-rope, generated from this fixture on GPU (CPU is within the
        // parity tolerance above); regenerate by printing gpu_logits if the
        // fixture weights ever change.
        const INTERLEAVED_LOGITS: [f32; 18] = [
            0.26534653,
            -0.09555817,
            -0.039089203,
            -0.33926773,
            1.0184975,
            0.295372,
            0.14318848,
            0.18154907,
            0.9362488,
            0.15462494,
            0.09391785,
            0.90491486,
            0.4603653,
            -0.8052864,
            -0.15103531,
            -0.45850372,
            0.9992676,
            -0.11646271,
        ];
        // The same fixture forwarded with split-half pe-rope (measured via a
        // temporary style override while bringing GLM-5.2 up) — kept as
        // evidence that qk_rope=4 separates the styles: max |delta| vs the
        // interleaved goldens is 6.3e-2, and the live logits must stay far
        // from these. Position-0 logits coincide by construction (rope is the
        // identity at position 0).
        const SPLIT_HALF_LOGITS: [f32; 18] = [
            0.26534653,
            -0.09555817,
            -0.039089203,
            -0.33854866,
            1.0210247,
            0.2813568,
            0.14783478,
            0.17350006,
            0.93655396,
            0.15768433,
            0.07234955,
            0.9055557,
            0.44625092,
            -0.8392143,
            -0.21441269,
            -0.4487648,
            1.0035286,
            -0.10030365,
        ];
        // Slightly looser than assert_close_vec: the goldens were captured on
        // one GPU generation and only need to pin the STYLE (6.3e-2 apart),
        // not exact kernel rounding.
        for (actual, expected) in gpu_logits.iter().zip(INTERLEAVED_LOGITS) {
            assert!(
                (actual - expected).abs() <= 2.0e-3,
                "glm-dsa logits diverged from the interleaved pe-rope goldens: \
                 actual {actual} expected {expected}"
            );
        }
        let split_half_delta = gpu_logits
            .iter()
            .zip(SPLIT_HALF_LOGITS)
            .map(|(actual, split)| (actual - split).abs())
            .fold(0.0f32, f32::max);
        assert!(
            split_half_delta > 2.0e-2,
            "glm-dsa fixture no longer distinguishes the pe-rope styles \
             (max logit delta vs split-half {split_half_delta:e}); raise qk_rope"
        );
    }

    /// Pins the int8-activation verdicts per architecture: glm-dsa keeps
    /// every dp4a fast path — measured clean on the real GLM-5.2-REAP50
    /// checkpoint (per-layer rel-L2 vs float activations stays <= ~1.3e-3
    /// through 78 layers; greedy decode coherent under both configs) and
    /// required for the grouped MoE path that expert streaming depends on —
    /// while deepseek2's massive activations keep it excluded. Gating glm
    /// off here would deadlock expert streaming against the grouped-MoE
    /// requirement (gpu.rs moe_f32_device bails).
    #[cfg(feature = "native-cuda")]
    #[test]
    fn native_cuda_int8_activation_paths_allowed_for_glm_dsa_not_deepseek2() {
        use hi_gguf::GgufFile;

        let glm_path = tempfile_path("gpu-glm-dsa-int8-predicate");
        write_reference_glm_dsa(&glm_path, false);
        let glm_gguf = GgufFile::open(&glm_path).unwrap();
        let glm_model = crate::gpu::CudaQwenGpuModel::from_gguf(&glm_gguf).unwrap();
        assert!(glm_model.int8_activation_paths_allowed());

        let ds2_path = tempfile_path("gpu-deepseek2-int8-predicate");
        write_reference_deepseek_true_mla(&ds2_path);
        let ds2_gguf = GgufFile::open(&ds2_path).unwrap();
        let ds2_model = crate::gpu::CudaQwenGpuModel::from_gguf(&ds2_gguf).unwrap();
        assert!(!ds2_model.int8_activation_paths_allowed());
    }

    /// Real-checkpoint GLM-5.2 greedy probe (env-gated like the hi-local real
    /// smokes; skips unless `HI_GLM_DSA_REAL_GGUF` points at shard 1 of a
    /// glm-dsa split GGUF). Run with `HI_CUDA_EXPERT_STREAMING=1` and an
    /// `HI_CUDA_EXPERT_POOL_BYTES` sized for the GPU; prints load time and
    /// greedy continuations + decode rates for a few factual prompts so rope
    /// style / int8 A/Bs can be judged by coherence.
    #[cfg(feature = "native-cuda")]
    #[test]
    fn native_cuda_glm_dsa_real_model_greedy_probe() {
        use hi_gguf::GgufFile;
        use std::time::Instant;

        let Ok(path) = std::env::var("HI_GLM_DSA_REAL_GGUF") else {
            eprintln!("skipping glm-dsa real-model probe; set HI_GLM_DSA_REAL_GGUF");
            return;
        };
        let max_new = std::env::var("HI_GLM_DSA_REAL_MAX_TOKENS")
            .ok()
            .and_then(|value| value.parse::<usize>().ok())
            .unwrap_or(32);
        let started = Instant::now();
        let gguf = GgufFile::open(Path::new(&path)).unwrap();
        let eos = gguf.metadata_u32("tokenizer.ggml.eos_token_id");
        let tokenizer_host =
            crate::qwen_cpu::QwenCpuReference::from_gguf_tokenizer_only(&gguf).unwrap();
        let tokenizer = tokenizer_host.tokenizer();
        let model = crate::gpu::CudaQwenGpuModel::from_gguf(&gguf).unwrap();
        eprintln!(
            "glm-dsa real model loaded in {:.1}s",
            started.elapsed().as_secs_f64()
        );

        let prompts = [
            "The capital of France is",
            "Water is made of two elements: hydrogen and",
            "The first person to walk on the Moon was",
            "Counting by twos: 2, 4, 6, 8,",
        ];
        for prompt in prompts {
            let input_ids = tokenizer.encode(prompt).unwrap();
            let step = Instant::now();
            // Paged KV: the non-paged greedy path preallocates the KV cache
            // for the FULL model context (1M tokens on GLM-5.2 — hundreds of
            // GB); the paged path allocates by actual sequence need.
            let output = model
                .generate_greedy_tokens_paged(&input_ids, max_new, eos, 16)
                .unwrap();
            let elapsed = step.elapsed().as_secs_f64();
            let text = tokenizer.decode(&output).unwrap();
            eprintln!(
                "[{} new tokens, {:.2} tok/s] {prompt:?} -> {text:?}",
                output.len(),
                output.len() as f64 / elapsed
            );
            assert!(!output.is_empty(), "no tokens generated for {prompt:?}");
        }
    }

    /// Rank-3 Q4_K expert tensor with deterministic random bytes and pinned
    /// (small) block scales so activations stay finite. The bytes only need to
    /// be IDENTICAL between the resident and streamed loads.
    #[cfg(feature = "native-cuda")]
    fn tensor_q4k_experts(
        name: &str,
        in_dim: usize,
        out_dim: usize,
        experts: usize,
        seed: u64,
    ) -> TestTensor {
        use rand::rngs::StdRng;
        use rand::{RngCore, SeedableRng};
        const BLOCK_BYTES: usize = 144;
        let elements = in_dim * out_dim * experts;
        assert_eq!(elements % 256, 0);
        let blocks = elements / 256;
        let mut bytes = vec![0u8; blocks * BLOCK_BYTES];
        let mut rng = StdRng::seed_from_u64(seed);
        rng.fill_bytes(&mut bytes);
        for block in 0..blocks {
            let base = block * BLOCK_BYTES;
            // d = f16 0x1C00 (~0.0039), dmin = 0x1800 (~0.00098): small enough
            // that random quants cannot blow up the forward.
            bytes[base] = 0x00;
            bytes[base + 1] = 0x1C;
            bytes[base + 2] = 0x00;
            bytes[base + 3] = 0x18;
        }
        TestTensor {
            name: name.to_string(),
            dims: vec![in_dim as u64, out_dim as u64, experts as u64],
            dtype: 12,
            offset: 0,
            bytes,
        }
    }

    /// Tiny qwen3moe-style model whose routed experts are Q4_K rank-3 tensors:
    /// the shape the expert-streaming pool serves. embed = ff = 256 keeps every
    /// projection's reduction dim at the grouped-GEMV 256-multiple.
    #[cfg(feature = "native-cuda")]
    fn write_reference_moe_streaming_fixture(path: &Path) {
        const EMBED: usize = 256;
        const EXPERTS: usize = 4;
        let mut tensors = vec![
            tensor_f16_exact(
                "token_embd.weight",
                vec![EMBED as u64, 3],
                &qwen35_fixture_values(EMBED * 3, 61),
            ),
            tensor_f32(
                "output_norm.weight",
                vec![EMBED as u64],
                &qwen35_fixture_norm_values(EMBED, 62),
            ),
        ];
        for layer in 0..2usize {
            let p = format!("blk.{layer}");
            let seed = 63 + (layer as u32) * 40;
            tensors.extend([
                tensor_f32(
                    &format!("{p}.attn_norm.weight"),
                    vec![EMBED as u64],
                    &qwen35_fixture_norm_values(EMBED, seed),
                ),
                tensor_f32(
                    &format!("{p}.ffn_norm.weight"),
                    vec![EMBED as u64],
                    &qwen35_fixture_norm_values(EMBED, seed + 1),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_q.weight"),
                    vec![EMBED as u64, EMBED as u64],
                    &qwen35_fixture_values(EMBED * EMBED, seed + 2),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_k.weight"),
                    vec![EMBED as u64, EMBED as u64],
                    &qwen35_fixture_values(EMBED * EMBED, seed + 3),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_v.weight"),
                    vec![EMBED as u64, EMBED as u64],
                    &qwen35_fixture_values(EMBED * EMBED, seed + 4),
                ),
                tensor_f16_exact(
                    &format!("{p}.attn_output.weight"),
                    vec![EMBED as u64, EMBED as u64],
                    &qwen35_fixture_values(EMBED * EMBED, seed + 5),
                ),
                tensor_f32(
                    &format!("{p}.ffn_gate_inp.weight"),
                    vec![EMBED as u64, EXPERTS as u64],
                    &qwen35_fixture_values(EMBED * EXPERTS, seed + 6),
                ),
                tensor_q4k_experts(
                    &format!("{p}.ffn_gate_exps.weight"),
                    EMBED,
                    EMBED,
                    EXPERTS,
                    u64::from(seed) + 7,
                ),
                tensor_q4k_experts(
                    &format!("{p}.ffn_up_exps.weight"),
                    EMBED,
                    EMBED,
                    EXPERTS,
                    u64::from(seed) + 8,
                ),
                tensor_q4k_experts(
                    &format!("{p}.ffn_down_exps.weight"),
                    EMBED,
                    EMBED,
                    EXPERTS,
                    u64::from(seed) + 9,
                ),
            ]);
        }
        write_moe_streaming_gguf(path, tensors);
    }

    #[cfg(feature = "native-cuda")]
    fn write_moe_streaming_gguf(path: &Path, tensors: Vec<TestTensor>) {
        let mut data = Vec::new();
        let tensors = tensors
            .into_iter()
            .map(|mut tensor| {
                pad_to_alignment(&mut data, 32);
                tensor.offset = data.len() as u64;
                data.extend_from_slice(&tensor.bytes);
                tensor
            })
            .collect::<Vec<_>>();

        let mut bytes = Vec::new();
        bytes.extend_from_slice(b"GGUF");
        write_u32(&mut bytes, 3);
        write_u64(&mut bytes, tensors.len() as u64);
        write_u64(&mut bytes, 15);

        write_kv_string(&mut bytes, "general.architecture", "qwen3moe");
        write_kv_string(&mut bytes, "general.name", "moe-streaming-fixture");
        write_kv_u32(&mut bytes, "general.alignment", 32);
        write_kv_u32(&mut bytes, "general.file_type", 15);
        write_kv_u32(&mut bytes, "qwen3moe.context_length", 128);
        write_kv_u32(&mut bytes, "qwen3moe.embedding_length", 256);
        write_kv_u32(&mut bytes, "qwen3moe.feed_forward_length", 256);
        write_kv_u32(&mut bytes, "qwen3moe.block_count", 2);
        write_kv_u32(&mut bytes, "qwen3moe.attention.head_count", 2);
        write_kv_u32(&mut bytes, "qwen3moe.attention.head_count_kv", 2);
        write_kv_f32(
            &mut bytes,
            "qwen3moe.attention.layer_norm_rms_epsilon",
            1.0e-6,
        );
        write_kv_f32(&mut bytes, "qwen3moe.rope.freq_base", 10_000.0);
        write_kv_u32(&mut bytes, "qwen3moe.expert_count", 4);
        write_kv_u32(&mut bytes, "qwen3moe.expert_used_count", 2);
        write_kv_string_array(&mut bytes, "tokenizer.ggml.tokens", &["a", "b", "c"]);

        for tensor in tensors {
            write_string(&mut bytes, &tensor.name);
            write_u32(&mut bytes, tensor.dims.len() as u32);
            for dim in tensor.dims {
                write_u64(&mut bytes, dim);
            }
            write_u32(&mut bytes, tensor.dtype);
            write_u64(&mut bytes, tensor.offset);
        }

        pad_to_alignment(&mut bytes, 32);
        bytes.extend(data);
        fs::write(path, bytes).unwrap();
    }

    /// The expert-streaming pool must be invisible to the math: a tiny pool
    /// (5 slots vs 24 distinct experts, forcing constant eviction) generates
    /// BIT-identical logits and greedy tokens vs the fully-resident load of
    /// the same file.
    #[cfg(feature = "native-cuda")]
    #[test]
    fn native_cuda_expert_streaming_matches_resident() {
        use hi_gguf::GgufFile;

        // Both loads must keep experts quantized (grouped dp4a path); the
        // f16-residency conversion would otherwise route the tiny resident
        // model through different math. Same precedent as the MMQ tests.
        unsafe { std::env::set_var("HI_CUDA_WEIGHTS_F16", "0") };

        let path = tempfile_path("gpu-moe-streaming");
        write_reference_moe_streaming_fixture(&path);
        let gguf = GgufFile::open(&path).unwrap();

        let resident = crate::gpu::CudaQwenGpuModel::from_gguf_with_expert_streaming(
            &gguf,
            None,
            crate::gpu::KvPoolBound::default(),
        )
        .unwrap();
        // Per-expert bytes: 256x256 Q4_K = 256 blocks x 144 = 36,864.
        let streamed = crate::gpu::CudaQwenGpuModel::from_gguf_with_expert_streaming(
            &gguf,
            Some(14 * 36_864),
            crate::gpu::KvPoolBound::default(),
        )
        .unwrap();

        assert!(resident.has_matrix("blk.0.ffn_gate_exps.0.weight"));
        assert!(!streamed.has_matrix("blk.0.ffn_gate_exps.0.weight"));

        let resident_logits = resident.full_context_logits_host(&[0, 1, 2]).unwrap();
        let streamed_logits = streamed.full_context_logits_host(&[0, 1, 2]).unwrap();
        assert_eq!(resident_logits, streamed_logits);
        assert!(resident_logits.iter().all(|value| value.is_finite()));

        assert_eq!(
            resident.generate_greedy_tokens(&[1], 4, None).unwrap(),
            streamed.generate_greedy_tokens(&[1], 4, None).unwrap()
        );

        let stats = streamed.expert_pool_stats().unwrap();
        assert!(stats.misses > 0);
        assert!(stats.evictions > 0, "pool never evicted; stats: {stats:?}");
        assert!(stats.hits > 0);
    }

