        write_kv_u32(&mut bytes, "tokenizer.ggml.eos_token_id", 2);
        write_kv_u32(&mut bytes, "tokenizer.ggml.unknown_token_id", 2);
        write_kv_string_array(&mut bytes, "tokenizer.ggml.tokens", &["a", "b", "c"]);

